const messages = $input.all();
const transcriptText = messages.map(item => `${item.json.role.toUpperCase()}: ${item.json.content}`).join('\n\n');

return [{
    json: {
        conversation_id: messages[0].json.conversation_id, // Pass the ID forward
        user_id: $('Webhook').first().json.body.user_id,
        transcript: transcriptText
    }
}];
